import type { Metadata } from "next";
import BusServiceStatusClient from "./BusServiceStatusClient";

export const metadata: Metadata = {
  title: "運行情報・遅延運休案内 | 都営バス",
  description:
    "都営バスの運行状況をリアルタイムで確認。系統別の平常運転・遅延・運休・迂回の状況、重要なお知らせ、遅延の経緯（バスロケ）を確認し、運行情報メールの通知も設定できます。",
};

// Server Component shell。すべての対話 UI（onValueChange / onSelect / onCheckedChange
// などの function props）は "use client" の BusServiceStatusClient 側に閉じ込めてあるので
// `next build`（RSC）が壊れない。
export default function BusServiceStatusPage() {
  return (
    <main className="min-h-screen bg-muted/30 text-foreground">
      <div className="mx-auto w-full max-w-md bg-background shadow-sm">
        <BusServiceStatusClient />
      </div>
    </main>
  );
}

"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconArrowsSplit,
  IconBan,
  IconBellRinging,
  IconCircleCheck,
  IconClock,
  IconInfoCircle,
  IconRefresh,
  IconRoute,
} from "@tabler/icons-react";

import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  ListCard,
  PageHeader,
  SegmentedControl,
  Separator,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  StatGroup,
  Switch,
  Timeline,
  TimelineDescription,
  TimelineItem,
  TimelineTime,
  TimelineTitle,
} from "@gunjo/ui";

import {
  LAST_UPDATED,
  LEVEL_META,
  ROUTES,
  type RouteStatus,
  type ServiceLevel,
} from "./data";

/** レベル → Badge variant + アイコン。色だけに依存させないため必ずアイコンを添える。 */
const LEVEL_BADGE: Record<
  ServiceLevel,
  { variant: "success" | "warning" | "info" | "destructive"; icon: React.ReactNode }
> = {
  normal: { variant: "success", icon: <IconCircleCheck aria-hidden /> },
  delay: { variant: "warning", icon: <IconClock aria-hidden /> },
  detour: { variant: "info", icon: <IconArrowsSplit aria-hidden /> },
  suspended: { variant: "destructive", icon: <IconBan aria-hidden /> },
};

/** ListCard の左アクセントレール用 severity。 */
const LEVEL_SEVERITY: Record<
  ServiceLevel,
  "success" | "warning" | "info" | "critical"
> = {
  normal: "success",
  delay: "warning",
  detour: "info",
  suspended: "critical",
};

function LevelBadge({ level }: { level: ServiceLevel }) {
  const meta = LEVEL_META[level];
  const badge = LEVEL_BADGE[level];
  return (
    <Badge variant={badge.variant} icon={badge.icon}>
      {meta.label}
    </Badge>
  );
}

type FilterValue = "all" | "disruption";

export default function BusServiceStatusClient() {
  const [filter, setFilter] = React.useState<FilterValue>("all");
  const [mailOptIn, setMailOptIn] = React.useState(false);
  const [selected, setSelected] = React.useState<RouteStatus | null>(null);
  const [updatedAt, setUpdatedAt] = React.useState(LAST_UPDATED);
  const [updating, setUpdating] = React.useState(false);

  const counts = React.useMemo(() => {
    const c = { normal: 0, delay: 0, detour: 0, suspended: 0 };
    for (const r of ROUTES) c[r.level] += 1;
    return c;
  }, []);

  const disruptedCount = counts.delay + counts.detour + counts.suspended;

  // 全体の運行状況レベル（最悪のレベルに合わせる）。
  const overall: ServiceLevel =
    counts.suspended > 0
      ? "suspended"
      : counts.detour > 0 || counts.delay > 0
        ? "delay"
        : "normal";

  const visibleRoutes = React.useMemo(() => {
    const rows =
      filter === "disruption"
        ? ROUTES.filter((r) => r.level !== "normal")
        : ROUTES;
    // 運休 → 迂回 → 遅延 → 平常 の順（深刻なものを上に）。
    const rank: Record<ServiceLevel, number> = {
      suspended: 0,
      detour: 1,
      delay: 2,
      normal: 3,
    };
    return [...rows].sort((a, b) => rank[a.level] - rank[b.level]);
  }, [filter]);

  const handleRefresh = () => {
    setUpdating(true);
    // 実機では再フェッチ。ここでは更新時刻だけ進める簡易デモ。
    window.setTimeout(() => {
      const now = new Date();
      setUpdatedAt(
        `${String(now.getHours()).padStart(2, "0")}:${String(
          now.getMinutes()
        ).padStart(2, "0")}`
      );
      setUpdating(false);
    }, 600);
  };

  const overallAlert = {
    normal: {
      variant: "success" as const,
      icon: <IconCircleCheck aria-hidden />,
      title: "平常運転",
      body: "現在、全系統で大きな運行の乱れはありません。",
    },
    delay: {
      variant: "warning" as const,
      icon: <IconAlertTriangle aria-hidden />,
      title: "一部遅延・迂回",
      body: `${disruptedCount}系統で遅延・迂回・運休が発生しています。下の一覧でご確認ください。`,
    },
    detour: {
      variant: "warning" as const,
      icon: <IconAlertTriangle aria-hidden />,
      title: "一部遅延・迂回",
      body: `${disruptedCount}系統で遅延・迂回・運休が発生しています。`,
    },
    suspended: {
      variant: "destructive" as const,
      icon: <IconBan aria-hidden />,
      title: "一部運休あり",
      body: `${counts.suspended}系統が運休中、ほか${
        counts.delay + counts.detour
      }系統で遅延・迂回が発生しています。`,
    },
  }[overall];

  return (
    <div className="flex min-h-screen flex-col pb-[env(safe-area-inset-bottom)]">
      <PageHeader
        title="運行情報"
        subtitle="都営バス（東京都交通局）"
        onBack={() => undefined}
        actions={
          <Button
            variant="ghost"
            size="icon"
            onClick={handleRefresh}
            aria-label="運行情報を更新"
            disabled={updating}
          >
            <IconRefresh
              className={updating ? "animate-spin" : undefined}
              aria-hidden
            />
          </Button>
        }
      />

      <div className="flex flex-col gap-4 px-4 py-4">
        {/* 全体の運行状況サマリ */}
        <section aria-labelledby="overall-heading">
          <h2 id="overall-heading" className="sr-only">
            全体の運行状況
          </h2>
          <Alert variant={overallAlert.variant}>
            {overallAlert.icon}
            <AlertTitle as="h2">{overallAlert.title}</AlertTitle>
            <AlertDescription>
              <p>{overallAlert.body}</p>
              <p className="mt-1 flex items-center gap-1 text-[11px] opacity-80">
                <IconClock className="size-3" aria-hidden />
                最終更新 {updatedAt}（バスロケ）
              </p>
            </AlertDescription>
          </Alert>

          <div className="mt-3">
            <StatGroup
              cols={{ base: 4 }}
              card
              items={[
                { label: "平常", value: counts.normal },
                { label: "遅延", value: counts.delay },
                { label: "迂回", value: counts.detour },
                { label: "運休", value: counts.suspended },
              ]}
            />
          </div>
        </section>

        {/* 重要なお知らせ */}
        <section aria-labelledby="notice-heading">
          <h2 id="notice-heading" className="sr-only">
            重要なお知らせ
          </h2>
          <Alert variant="destructive">
            <IconAlertTriangle aria-hidden />
            <AlertTitle as="h2">重要なお知らせ：大雪の影響</AlertTitle>
            <AlertDescription>
              <p>
                大雪による路面凍結のため、
                <span className="font-medium">都03（四谷駅前〜晴海埠頭）</span>
                は全便運休しています。運転再開は未定です。最新の情報は当ページでご確認ください。
              </p>
            </AlertDescription>
          </Alert>
        </section>

        <Separator />

        {/* 系統別の運行状況 */}
        <section aria-labelledby="routes-heading" className="flex flex-col gap-3">
          <div className="flex items-center justify-between">
            <h2
              id="routes-heading"
              className="flex items-center gap-1.5 text-sm font-semibold text-foreground"
            >
              <IconRoute className="size-4 text-muted-foreground" aria-hidden />
              系統別の運行状況
            </h2>
            <span className="text-xs text-muted-foreground tabular-nums">
              {visibleRoutes.length}件
            </span>
          </div>

          {/* 絞り込み 全て / 遅延・運休のみ */}
          <SegmentedControl
            aria-label="運行状況の絞り込み"
            size="lg"
            value={filter}
            onValueChange={(v) => setFilter(v as FilterValue)}
            options={[
              { value: "all", label: `全系統 (${ROUTES.length})` },
              {
                value: "disruption",
                label: `遅延・運休のみ (${disruptedCount})`,
              },
            ]}
          />

          <ul className="flex flex-col gap-2" aria-label="系統別の運行状況一覧">
            {visibleRoutes.map((route) => (
              <li key={route.id}>
                <ListCard
                  severity={LEVEL_SEVERITY[route.level]}
                  leading={
                    <span
                      className="inline-flex h-9 min-w-[2.75rem] items-center justify-center rounded-md bg-secondary px-2 text-sm font-bold tabular-nums text-secondary-foreground"
                      aria-hidden
                    >
                      {route.id}
                    </span>
                  }
                  title={
                    <span>
                      <span className="sr-only">系統{route.id}・</span>
                      {route.name}
                    </span>
                  }
                  description={
                    route.level === "normal" ? (
                      "平常どおり運行しています"
                    ) : (
                      <>
                        {route.affectedSection && (
                          <span className="block">
                            対象区間：{route.affectedSection}
                          </span>
                        )}
                        {route.reason && (
                          <span className="block">{route.reason}</span>
                        )}
                      </>
                    )
                  }
                  status={<LevelBadge level={route.level} />}
                  meta={
                    route.level === "normal" ? undefined : route.statusLabel
                  }
                  onSelect={
                    route.level === "normal"
                      ? undefined
                      : () => setSelected(route)
                  }
                  trailing={route.level === "normal" ? null : undefined}
                />
              </li>
            ))}
          </ul>

          {visibleRoutes.length === 0 && (
            <Alert variant="success">
              <IconCircleCheck aria-hidden />
              <AlertTitle as="p">遅延・運休はありません</AlertTitle>
              <AlertDescription>
                <p>現在、運行を見合わせている系統はありません。</p>
              </AlertDescription>
            </Alert>
          )}
        </section>

        <Separator />

        {/* 更新・通知 */}
        <section aria-labelledby="notify-heading" className="flex flex-col gap-3">
          <h2
            id="notify-heading"
            className="flex items-center gap-1.5 text-sm font-semibold text-foreground"
          >
            <IconBellRinging className="size-4 text-muted-foreground" aria-hidden />
            更新・通知
          </h2>

          <div className="flex items-center justify-between gap-3 rounded-lg border border-border bg-card p-3">
            <div className="min-w-0">
              <p className="text-xs text-muted-foreground">最終更新</p>
              <p className="text-sm font-medium tabular-nums">
                {updatedAt}{" "}
                <span className="text-xs font-normal text-muted-foreground">
                  時点（バスロケ）
                </span>
              </p>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={handleRefresh}
              disabled={updating}
            >
              <IconRefresh
                className={updating ? "animate-spin" : undefined}
                aria-hidden
              />
              {updating ? "更新中…" : "更新"}
            </Button>
          </div>

          <div className="rounded-lg border border-border bg-card p-3">
            <Switch
              checked={mailOptIn}
              onCheckedChange={setMailOptIn}
              label="運行情報メールを受け取る"
              description="遅延・運休・運転再開などの更新を、対象路線についてメールでお知らせします。"
            />
          </div>
        </section>
      </div>

      {/* 運行情報の詳細・経緯（バスロケのログ） */}
      <Sheet
        open={selected !== null}
        onOpenChange={(open) => {
          if (!open) setSelected(null);
        }}
      >
        <SheetContent side="bottom" className="max-h-[85vh] overflow-y-auto">
          {selected && (
            <>
              <SheetHeader>
                <div className="flex items-center gap-2">
                  <span className="inline-flex h-8 min-w-[2.75rem] items-center justify-center rounded-md bg-secondary px-2 text-sm font-bold tabular-nums text-secondary-foreground">
                    {selected.id}
                  </span>
                  <LevelBadge level={selected.level} />
                </div>
                <SheetTitle className="mt-2">{selected.name}</SheetTitle>
                <SheetDescription>
                  {selected.statusLabel}
                  {selected.affectedSection
                    ? `・対象区間：${selected.affectedSection}`
                    : ""}
                </SheetDescription>
              </SheetHeader>

              {selected.reason && (
                <Alert
                  variant={
                    selected.level === "suspended" ? "destructive" : "warning"
                  }
                  className="mt-4"
                >
                  {selected.level === "suspended" ? (
                    <IconBan aria-hidden />
                  ) : (
                    <IconInfoCircle aria-hidden />
                  )}
                  <AlertTitle as="p">理由</AlertTitle>
                  <AlertDescription>
                    <p>{selected.reason}</p>
                  </AlertDescription>
                </Alert>
              )}

              <div className="mt-5">
                <h3 className="mb-3 text-sm font-semibold text-foreground">
                  運行情報の経緯
                </h3>
                {selected.log && selected.log.length > 0 ? (
                  <Timeline>
                    {selected.log.map((entry, i) => {
                      const isLast = i === selected.log!.length - 1;
                      return (
                        <TimelineItem
                          key={`${entry.time}-${i}`}
                          connector={!isLast}
                          variant={
                            !entry.done
                              ? "active"
                              : selected.level === "suspended"
                                ? "destructive"
                                : "warning"
                          }
                        >
                          <TimelineTime>{entry.time}</TimelineTime>
                          <TimelineTitle>{entry.label}</TimelineTitle>
                          {entry.detail && (
                            <TimelineDescription>
                              {entry.detail}
                            </TimelineDescription>
                          )}
                        </TimelineItem>
                      );
                    })}
                  </Timeline>
                ) : (
                  <p className="text-sm text-muted-foreground">
                    経緯の記録はありません。
                  </p>
                )}
              </div>

              <p className="mt-4 flex items-center gap-1 text-xs text-muted-foreground">
                <IconClock className="size-3" aria-hidden />
                最終更新 {updatedAt}（バスロケ）
              </p>
            </>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}

// 都営バス 運行情報のサンプルデータ（実在しそうな系統・区間・理由で構成）。
// 純データのみ（function prop なし）なので Server / Client どちらからも import 可。

/** 運行状況レベル。平常 → 遅延 → 迂回 → 運休 のエスカレーション。 */
export type ServiceLevel = "normal" | "delay" | "detour" | "suspended";

export interface RouteStatus {
  /** 系統番号（渋88 など）。 */
  id: string;
  /** 系統名（区間）。 */
  name: string;
  /** 方面・エリア（フィルタ用）。 */
  area: "渋谷" | "新宿" | "品川" | "江東";
  level: ServiceLevel;
  /** 状況ラベル（平常運転 / 約10分遅れ / 一部運休 など）。 */
  statusLabel: string;
  /** 影響している区間（運休・遅延の対象区間）。 */
  affectedSection?: string;
  /** 遅延・運休の理由。 */
  reason?: string;
  /** 経緯ログ（バスロケ）。disruption のある系統のみ。 */
  log?: Array<{ time: string; label: string; detail?: string; done?: boolean }>;
}

export const LEVEL_META: Record<
  ServiceLevel,
  { label: string; tone: "success" | "warning" | "destructive" | "info" }
> = {
  normal: { label: "平常運転", tone: "success" },
  delay: { label: "遅延", tone: "warning" },
  detour: { label: "迂回", tone: "info" },
  suspended: { label: "運休", tone: "destructive" },
};

